form_load_with_database.csharp_equivalent:
public Form1()
{
    InitializeComponent();
    LoadInitialData();
}

private async void LoadInitialData()
{
    try
    {
        using (var connection = new OleDbConnection(@"Provider=Microsoft.ACE.OLEDB.12.0;Data Source=C:\data.mdb"))
        {
            await connection.OpenAsync();

            using (var command = new OleDbCommand("SELECT UserName FROM Users ORDER BY UserName", connection))
            using (var reader = await command.ExecuteReaderAsync())
            {
                comboBox1.Items.Clear();
                while (await reader.ReadAsync())
                {
                    comboBox1.Items.Add(reader["UserName"].ToString());
                }
            }
        }

        this.Text = $"User Management - {DateTime.Now:MM/dd/yyyy}";
    }
    catch (Exception ex)
    {
        MessageBox.Show($"Error loading data: {ex.Message}", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
    }
}

